import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import './Login.css'; // हा CSS इम्पॉर्ट करण्यासाठी आहे

function Login() {
  const [email, setEmail] = useState(""); 
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Freelancer"); 
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    setIsLoading(true);

    try {
      const response = await fetch('http://localhost:3000/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password, role }),
      });

      const data = await response.json();

      if (response.ok) {
        // डॅशबोर्डसाठी डेटा सेव्ह करणे
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user)); 
        localStorage.setItem('userRole', data.user.role);
        
        alert("Login Successful! 🎉");
        navigate("/dashboard");
      } else {
        setError(data.msg || "Invalid Credentials");
      }
    } catch (error) {
      setError("Server शी संपर्क होत नाहीये. कृपया बॅकएंड चेक करा.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <h2 className="login-title">{role} Login</h2>
        
        {error && <div className="error-box">{error}</div>}
        
        <form onSubmit={handleLogin} className="login-form">
          <div className="form-group">
            <label className="input-label">Select Role</label>
            <select 
              className="login-select"
              value={role} 
              onChange={(e) => setRole(e.target.value)}
            >
              <option value="Freelancer">Freelancer</option>
              <option value="Client">Client (Hirer)</option>
            </select>
          </div>

          <div className="form-group">
            <input 
              type="email" 
              className="login-input"
              placeholder="Email Address" 
              value={email} 
              onChange={(e) => setEmail(e.target.value)} 
              required 
            />
          </div>
          
          <div className="form-group">
            <input 
              type="password" 
              className="login-input"
              placeholder="Password" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              required 
            />
          </div>

          <button type="submit" disabled={isLoading} className="login-submit-btn">
            {isLoading ? <span className="spinner"></span> : "Login Now"}
          </button>
        </form>
        
        <p className="signup-redirect">
          Don't have an account? <span onClick={() => navigate("/signup")} className="signup-link">Signup</span>
        </p>
      </div>
    </div>
  );
}

export default Login;
